var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흠……. 흐흠…….","JPN":"ふん……ふふん……","ENG":"Hm... Hmm...","TWN":"呵……呵呵……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 난 역시 즉흥 공연이 체질인가 봐. 시작하자마자 관객들이 모여들잖아.","JPN":"ふふっ。やっぱり私には即興公演が向いてるわね。始まったばかりなのに観客が集まってるじゃない。","ENG":"Fuu fuu. I’m so good at improvisational performances. Just as the performance is about to begin, the audience arrives.","TWN":"呵呵，我果然很會即興表演，表演才剛開始就吸引觀眾圍觀。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"소음 공해를 항의하러 온 건데, 머리에 총 맞았니?","JPN":"騒音公害に抗議しに来ただけなのに、さすがに迂闊すぎるんじゃないかしら？","ENG":"Excuse me, I’m here to complain about the strange noise. What’s the matter, did you take a bullet to the head?","TWN":"我是來抗議噪音汙染的！你是腦袋浸水嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드에서 쇠파이프에 두들겨 맞은 후유증이 심해서 그러려나.","JPN":"シャレードで鉄パイプに叩かれた後遺症がひどかったようね。","ENG":"Were the aftereffects of being beaten with that metal pipe in Charade so severe?","TWN":"還是你在查雷德被鐵管打到神智不清？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"뭐야, 류드밀라는 어디 가고 왜 실패작들만 득실거려?","JPN":"なによ、リュドミラはどこ？　なんで失敗作だけウジャウジャしてるの？","ENG":"What’s this? Where’s Lyudmila? Why are only the failed products here?","TWN":"搞什麼？盧德米拉呢？怎麼來的淨是些失敗品？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하긴 상관없나. 어차피 귀찮아지기 전에 정리할 생각이었고.","JPN":"まあ、いいか。どうせ面倒になる前に片付けるつもりだったし。","ENG":"Oh well, it doesn’t really matter! Anyway, I was thinking I’d take care of everything before it gets too annoying.","TWN":"不過也無所謂啦～反正我本來就打算在事情變複雜前，趕快先處理乾淨。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"지난번에는 전대장님이 막으셔서 무사히 돌아갔을 뿐이다. 그림자.","JPN":"この前は戦隊長が止めるから無事に帰れただけだ。シャドウ。","ENG":"Because the Commander stopped us last time, you were able to retreat. Shadow.","TWN":"暗影，上次是戰隊長阻止我，我才留你一條活路。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"두 번 다시 현실세계에 나타날 엄두도 못 내게 만들어 주지.","JPN":"二度と現実世界に現れようと思えないようにしてやろう。","ENG":"After this time, you won’t dare show your face in Normalside ever again.","TWN":"這次我會讓你再也不敢出現在現實世界！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음. 패잔병 주제에 기백이 대단한걸.","JPN":"ふうん。負け犬のくせに気迫だけは一人前ね。","ENG":"Hmm. You sure do have spirit for a soldier who has already lost.","TWN":"哈～區區一個殘兵敗將口氣還真大！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 옆에 있는 A타입을 믿고 설치는 거라면 그만두는 편이 좋을 거야.","JPN":"あなたのそばにいるAタイプを信じて出しゃばってるのなら、やめた方がいいわ。","ENG":"If that Type A next to you is the reason you’re so cocky, it’d be better for you to just give up now.","TWN":"你是仗勢有A型給你靠才敢囂張嗎？那我勸你還是收斂一點比較好～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"카운터로 각성했다고 해도…….","JPN":"カウンターとして覚醒したとしても……","ENG":"Even if she awakened as a Counter—","TWN":"就算她已經覺醒成制裁者……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……읏?!","JPN":"……うっ！？","ENG":"Ngh...?!","TWN":"……唔？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"왜 그래, 최고 단원님? 옛날보다 묵직한 소리에 놀라셨으려나?","JPN":"どうしたの？　首席奏者さん。昔よりどっしりとした音で驚いちゃった？","ENG":"What’s wrong, Elite Member? You seem surprised that the sound is louder than last time.","TWN":"你怎麼啦？是不是被這沉穩的聲音給嚇到啦？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"말할 줄 아는 짐승에 불과한 너희들이랑 다르게, 인간들은 발전이라는 걸 하거든.","JPN":"しゃべる獣に過ぎないあなたたちとは違って、人間は発展するものなの。","ENG":"Unlike you guys, who are nothing more than overly talkative savages, humans do this thing called development.","TWN":"人類是會進步的，和你們這種會說話的禽獸是不同的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"이전처럼 네 좋을 대로 농락당할 줄 알았다면 오산이야.","JPN":"今までのようにあなたの好き放題翻弄できると思ったら、大間違いよ。","ENG":"If you thought you could fool around like you did before, you’re mistaken.","TWN":"你以為我們還會像以前一樣被你耍著玩嗎？那可就大錯特錯囉～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드에서 사라졌던 네가 왜 그로니아에 있는 거지? 대답해.","JPN":"シャレードから消えたあなたが、なんでグロニアにいるの？　答えなさい。","ENG":"You disappeared back in Charade, why are you in Gronia now? Answer me.","TWN":"你不是從查雷德消失了嗎？為什麼會出現在格羅尼亞？回答我！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄? 어떠려나?","JPN":"さあ？　どうかしら。","ENG":"Well... How should I put it?","TWN":"誰知道？你想怎樣？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"서곡은 이미 끝났어. 그렇다면 다음은 본 연주가 시작될 차례지.","JPN":"序奏はすでに終わったわ。それなら次は主題部の番。","ENG":"The overture is already over. Now is time for the main performance to begin.","TWN":"序曲已經表演完畢，接下來就要進入正式表演囉～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"본 연주? 휘하 단원들도 전부 잃고 얹혀 사는 주제에?","JPN":"主題部？　他の団員も全部失って居候してるくせに？","ENG":"Main performance? You’re still saying that after the loss of your men?","TWN":"正式表演？在失去其他團員，而且寄人籬下的狀態下？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그야 내가 알 바 아니지. 내 몫은 벌써 끝마쳤거든.","JPN":"それは私の知ったことじゃないわ。私の分はもう終わってるから。","ENG":"I couldn't care less anymore. My role has already been completed.","TWN":"這不關我的事，我的部分已經結束囉～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……그래. 그렇단 말이지.","JPN":"……そう。そういうことね。","ENG":"...Very well. I see how it is.","TWN":"……很好，果然是這樣。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아. 처음부터 순순히 대답해 주리란 기대는 안 했어.","JPN":"大丈夫。最初から素直に話してくれるなんて期待はしてなかったもの。","ENG":"That’s fine. I never expected you to answer me in the first place.","TWN":"沒關係，反正我也不指望你會乖乖回答我。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"죽을 준비는 됐니, 셰나?","JPN":"死ぬ準備はできてる？　シェナ。","ENG":"Any last words, Shena?","TWN":"世娜，準備受死吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 이래서 류드밀라는 안 돼.","JPN":"ふふっ。これだからリュドミラは。","ENG":"Fuu fuu. This is why Lyudmila never does her job well.","TWN":"呵呵，盧德米拉這樣不行啦～"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"오냐오냐 해 주니 실패작 따위가 주제도 모르고 기어오르잖아.","JPN":"甘やかすから失敗作なんかが身の程も知らずに調子に乗るじゃない。","ENG":"She always goes easy on everyone, and that’s why this failed product seems to have forgotten its place.","TWN":"這樣放任你，害你現在都看不清楚自己是誰，明明是個失敗品，口氣還那麼大！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"침식파 반응 감지! 타이런트 타입입니다, 부전대장님!","JPN":"侵食波反応を感知！　タイラントタイプです、副戦隊長！","ENG":"Detecting Corruption ray response! Deputy Commander, it’s a Tyrant Type!","TWN":"感應到侵蝕波反應！是暴君類型，副戰隊長！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 지원군으로 거들먹거리는 건 그만둬 주지 않으려나.","JPN":"そう。援軍で威張るのはやめてもらえるかしら。","ENG":"I see. Could you please stop showing off with the reinforcement?","TWN":"嗯，你就是喜歡討救兵，仗勢欺人是吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지금부터 네가 상대하는 건 3종만 나타나도 무서워하는 요즘 애들이 아니니까.","JPN":"今からあなたを相手するのは第3種なんかでビビる最近の子どもたちじゃないの。","ENG":"From now on, you won’t be dealing with kids who quake in fear when a Category 3 appears.","TWN":"你現在的對手可不像最近的孩子們，光是看到3類就會嚇到屁滾尿流。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"얘들아, 전투 준비.","JPN":"みんな、戦闘に備えなさい。","ENG":"Kids, prepare for battle.","TWN":"孩子們，準備作戰！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"누가 먼저 저 쓰레기 머리에 총알 박아 넣나 시합해 볼까?","JPN":"誰が一番早くあのクズの頭に弾丸をぶちこめるか、競争しょう？","ENG":"Who can put a bullet in that scumbag’s head first?","TWN":"要來比賽看看，誰先把子彈打入那個垃圾的腦袋裡嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};